-- Migracion 030: limpieza de specs "crudas" volcadas sin filtrar por el sync
-- de MercadoLibre (src/app/api/ml/sync/route.ts) antes de que existiera
-- curacion. Estos 199 productos tenian atributos internos de
-- ML mezclados con las specs reales (ej. "Regalable", "Motivo de GTIN vacio",
-- "Es marca destacada/TOM", "SKU" duplicado, dimensiones "del paquete del
-- seller"), lo que se veia desprolijo al lado de los productos con specs
-- curadas a mano. Este script NO agrega ni inventa datos: solo remueve esas
-- etiquetas internas y deja el resto de los atributos (ya reales, ya
-- confirmados por ML) intactos, en el mismo orden.
-- No toca la columna description ni ningun otro producto.

-- MLA1511046247: Reposapies Cromado Para Barberia/peluquería Behmont (19 -> 10 specs)
update products set specs = '[{"label":"Marca","value":"BEHMONT"},{"label":"Color","value":"Cromado"},{"label":"Altura","value":"46 cm"},{"label":"Condición del ítem","value":"Nuevo"},{"label":"Largo","value":"31 cm"},{"label":"Color principal","value":"Blanco"},{"label":"Material","value":"Metal"},{"label":"Modelo","value":"REPOSAPIES"},{"label":"Peso","value":"2.475 kg"},{"label":"Ancho","value":"36 cm"}]'::jsonb where sku = 'MLA1511046247';

